PROCEDURE SoftwareEngineeringProcess
BEGIN
 // Activity 1: Communication
 requirements = PerformCommunication()

 // Activity 2: Planning
 projectPlan = PerformPlanning(requirements)

 // Activity 3: Modeling
 analysisModel = PerformAnalysis(requirements)
 designModel = PerformDesign(analysisModel)

 // Activity 4: Construction
 softwareCode = PerformCoding(designModel)
 testResults = PerformTesting(softwareCode)

 // Activity 5: Deployment
 DeploySoftware(softwareCode, testResults)

 RETURN projectPlan
END
